mapper.select:
SELECT 
FROM lesson_bookmarks
WHERE user_id = #{userId} AND lesson_id = #{lessonId}

mapper.update:
UPDATE lesson_bookmarks
SET user_id   = #{userId},
    lesson_id = #{lessonId}
WHERE bookmark_id = #{bookmarkId}

mapper.select:
SELECT COUNT(*)
FROM lesson_bookmarks lb
JOIN lessons l ON l.lesson_id = lb.lesson_id
JOIN curriculum_nodes cn ON cn.node_id = l.node_id
WHERE lb.user_id = #{userId}
 AND cn.subject_id = #{subjectId}
